<template>
    <div id="timetable">
        <!-- section title -->
        <h1>Working Timetable</h1>
        <table v-animate-onscroll="'animated fadeIn'">
            <!-- The date of the timetable -->
            <thead>
                <tr>
                    <th></th>
                    <th v-for="(d, index) in days" :key="index">{{d}}</th>
                </tr>
            </thead>
            <tbody>
                <tr v-for="(t, row) in period" :key="row">
                    <!-- time period -->
                    <td>{{t}}</td>
                    <!-- course -->
                    <template v-for="(d, col) in days">
                        <td 
                            :key="col"
                            v-if="getElement('repeat', row, col)"
                            :rowspan="getElement('span', row, col)"
                            :style="{ backgroundColor: getElement('color', row, col)}"
                        >
                            {{getElement('courseCode', row, col)}}
                        </td>
                    </template>
                </tr>
            </tbody>
        </table>
    </div>
</template>

<script>
export default {
    name:'Timetable',
    data() {
        return {
            // To determine whenever the timetable matrix is parsed or not
            parsed: false,
            // The timetable 2D matrix
            timetable: [[]],
            // courses list
            courses: [
                {
                    courseCode:'AIST5020',
                    times:[
                        {day:'Mo', start:'1230', end:'1530', venue:'Shaw College LT'},
                        {day:'Tu', start:'1630', end:'1730'},
                    ],
                    color: '#F19BC8',
                },
                {
                    courseCode:'ENGG5501',
                    times:[
                        {day:'Mo', start:'1530', end:'1730', venue:'Shaw College LT'},
                        {day:'Th', start:'1430', end:'1630'},
                    ],
                    color: '#71C0F9'
                },
                {
                    courseCode:'ENGG2760 (TA)',
                    times:[
                        {day:'Mo', start:'1730', end:'1830'},
                        {day:'Th', start:'1630', end:'1830'},
                    ],
                    color: '#FDEF71'
                },
                {
                    courseCode:'Meeting',
                    times:[
                        {day:'Mo', start:'1730', end:'1830'},
                        {day:'Tu', start:'1400', end:'1500'},
                        {day:'Th', start:'1000', end:'1100'},
                    ],
                    color: '#D5D5D5'
                },
                {
                    courseCode:'TA Office Hour',
                    times:[
                        {day:'Th', start:'1230', end:'1330'},
                    ],
                    color: '#FDEF71'
                },
            ],
            // days in a week
            days:['Monday', 'Tuesday', 'Wednesday', 'Thursday', 'Friday'],
            period:[
                '0900-0930', '0930-1000', '1000-1030', '1030-1100', '1100-1130', '1130-1200',
                '1200-1230', '1230-1300', '1300-1330', '1330-1400', '1400-1430', '1430-1500',
                '1500-1530', '1530-1600', '1600-1630', '1630-1700', '1700-1730', '1730-1800', '1800-1830',
            ],
        }
    },
    methods: {
        // Transfer the days to specific numbers
        dayToNumber(day){
            switch (day) {
                case 'Mo':
                    return 1
                case 'Tu':
                    return 2
                case 'We':
                    return 3
                case 'Th':
                    return 4
                case 'Fr':
                    return 5
                case 'Sa':
                    return 6
                case 'Su':
                    return 7
                default:
                    return -1
            }
        },

        // Initalise the timetable array
        initTimetable(){
            let element = {courseCode: '', color: 'transparent', span: 1}
            for(let i = 0; i < 19; i++){
                this.timetable[i] = []
                for(let j = 0; j < 5; j++){
                    this.timetable[i][j] = element
                }
            }
            // update the timetable matrix
            this.updateTimetable()
        },

        convertTimeToDecimal(t) {
            let hours = Math.floor(t / 100);
            let minutes = t % 100;
            let decimalMinutes = minutes / 60;
            let decimalTime = hours + decimalMinutes;
            return decimalTime;
        },

        // Get the courses data and place the event into timetable matrix
        updateTimetable(){
            this.courses.forEach(c => {   // for each courses
                let {courseCode, times, color} = c
                times.forEach(t => {    // for each course period
                    let {day, start, end} = t
                    let start_time = 9
                    
                    day = this.dayToNumber(day)                 // day number
                    start = this.convertTimeToDecimal(start)    // starting time represents in number
                    end = this.convertTimeToDecimal(end)        // ending time represents in number
                    
                    let span = (end - start) * 2    // number of rows have to span

                    let element = {courseCode, color, span}     // the element in timetable matrix
                    this.timetable[(start - start_time) * 2].splice(day - 1, 1, element)   // place the element into timetable matrix

                    // if there is a span, set the covered element's span to 0
                    for(let i = 1; i <= span - 1; i++){
                        element = {courseCode: '', color: '', span: 0}
                        this.timetable[(start - start_time) * 2 + i].splice(day - 1, 1, element)   // place the element into timetable matrix
                    }
                })
            });
            this.parsed = true  // the timetable was parsed
        },

        // Return the elements from timetable array
        getElement(e, i, j){
            if(!this.parsed){
                return ''
            }
            switch (e) {
                case 'courseCode':
                    return this.timetable[i][j].courseCode
                case 'color':
                    return this.timetable[i][j].color
                case 'span':
                    return this.timetable[i][j].span
                case 'repeat':
                    return this.timetable[i][j].span !== 0
                default:
                    return null
            }
        },

        // Send an ajax request to get the courses information
        getCourses(){
            // [no server]
            this.initTimetable()
            // fetch('http://127.0.0.1:8081/timetable').then(res => {
            //     return res.json()
            // }).then(json => {
            //     this.courses = json
            //     this.initTimetable()
            // }).catch(err => {
            //     console.error(err)
            // })
        }
    },
    mounted(){
        this.$nextTick(this.getCourses)
    }
}
</script>

