<template>
<div id="preprint-list">
    <h1>Pre-print</h1>
    <div class="preprint-container">
        <el-timeline>
            <div v-for="(i, index) in preprints" :key="i.id">
                <PublicationItem :item="i" :index="index" :itemStatus="itemStatus" :switchStatus="switchStatus"/>
            </div>
        </el-timeline>
    </div>
</div>
</template>

<script>
import PublicationItem from './PublicationItem.vue'

export default {
    name: 'PreprintList',
    components: { PublicationItem },
    data() {
        return {
            itemStatus: [],
            preprints: [
                {
                    id: "huang2024far",
                    name: 'How Far Are We on the Decision-Making of LLMs? Evaluating LLM\' Gaming Ability in Multi-Agent Environments',
                    authors: ["Jen-tse Huang", "Eric John Li", "Man Ho Lam", "Tian Liang", "Wenxuan Wang", "Youliang Yuan", "Wenxiang Jiao", "Xing Wang", "Zhaopeng Tu", "Michael R. Lyu"],
                    figname: "huang2024far.png",
                    conference: "arXiv, 2024",
                    paper: "arXiv",
                    paperLink: 'https://arxiv.org/abs/2403.11807',
                    codeLink: 'https://github.com/CUHK-ARISE/GAMABench',
                },
            ]
        }
    },
    methods: {
        switchStatus(index){
            let status = this.itemStatus[index] === '' ? 'collapsed' : ''
            this.itemStatus.forEach((e, i) => {
                if(index === i){
                    this.itemStatus.splice(i, 1, status)
                }else{
                    this.itemStatus.splice(i, 1, 'collapsed')
                }
            })
        }
    },
    mounted() {
        for(let i = 0; i < this.items.length; i++){
            this.itemStatus.push('collapsed')
        }
    },
}
</script>

